SELECT FROM member_user WHERE id IN
#{id}
ORDER BY id DESC

SELECT 
FROM member_user


        AND status = #{status}


        AND (
            username LIKE CONCAT(#{keyword}, '%')
            OR mail LIKE CONCAT(#{keyword}, '%')
        )


        AND (
            created_at < #{cursorCreatedAt}
            OR (created_at = #{cursorCreatedAt} AND id < #{cursorId})
        )


ORDER BY created_at DESC, id DESC
LIMIT #{limit}

