INSERT INTO member_user (
    username, mail, password_hash, status, balance, last_login_at, last_seen_at
) VALUES (
    #{username}, #{mail}, #{passwordHash}, #{status}, #{balance}, #{lastLoginAt}, #{lastSeenAt}
)

mapper.update:
UPDATE member_user
SET status = #{status}
WHERE id = #{id}

UPDATE member_user
SET last_login_at = #{loginAt},
    last_seen_at = #{lastSeenAt}
WHERE id = #{id}

UPDATE member_user
SET last_seen_at = #{lastSeenAt}
WHERE id = #{id}

UPDATE member_user
SET last_login_at = CASE
        WHEN #{lastLoginAt} IS NULL THEN last_login_at
        ELSE #{lastLoginAt}
    END,
    last_seen_at = CASE
        WHEN #{lastSeenAt} IS NULL THEN last_seen_at
        ELSE #{lastSeenAt}
    END
WHERE id = #{id}

UPDATE member_user
SET balance = #{balance}
WHERE id = #{id}

UPDATE member_user
SET balance = balance - #{amount}
WHERE id = #{id}
  AND status = 'ACTIVE'
  AND balance = #{beforeBalance}
  AND balance >= #{amount}
